// ============================================================
// FILTER BY INDUSTRY (activity field)
// ============================================================
// The ransomware.live API uses the 'activity' field for
// sector/industry classification. This node filters to
// only the industries relevant to our audience.
//
// Customize the targetIndustries array to match your
// organization or the demo you want to show.
// ============================================================

const targetIndustries = [
  'manufacturing',
  'healthcare',
  'health',
  'hospital',
  'medical',
  'finance',
  'financial',
  'banking',
  'insurance',
  'technology',
  'software',
  'IT services',
  'energy',
  'oil',
  'utilities',
  'government',
  'education',
  'construction',
  'legal',
  'retail',
  'transportation',
  'logistics'
];

const items = $input.all();
const filtered = [];

for (const item of items) {
  const activity = (item.json.activity || '').toLowerCase();

  if (!activity) continue;

  const matches = targetIndustries.some(ind =>
    activity.includes(ind.toLowerCase())
  );

  if (matches) {
    filtered.push(item);
  }
}

if (filtered.length === 0) {
  return [{ json: { message: 'No victims found in target industries', count: 0 } }];
}

return filtered;

// ============================================================
// BUILD ENHANCED CONSOLIDATED THREAT BRIEF
// ============================================================
// Creates a visually compelling intelligence report with:
// - Executive Dashboard with key metrics
// - Threat Level Assessment
// - Geographic Distribution analysis
// - Industry Impact breakdown
// - Timeline analysis
// - Detailed group profiles with threat intelligence
// ============================================================

const items = $input.all();
const now = new Date().toISOString().split('T')[0];

// ---- Collect all group data with their victims ----
const groupBriefs = [];
let totalVictims = 0;
const countriesSet = new Set();
const industriesMap = {};
const discoveryDates = [];

for (const item of items) {
  const profile = item.json;

  let victims = [];
  let pairedData = null;
  try {
    pairedData = $('Extract Unique Groups1').item;
    if (pairedData && pairedData.json && pairedData.json.victims) {
      victims = pairedData.json.victims;
      totalVictims += victims.length;

      // Collect analytics data
      victims.forEach(v => {
        if (v.country) countriesSet.add(v.country);
        if (v.activity) {
          industriesMap[v.activity] = (industriesMap[v.activity] || 0) + 1;
        }
        if (v.discovered) discoveryDates.push(new Date(v.discovered));
      });
    }
  } catch (e) {
    // Fallback: no paired data available
  }

  const groupName = (pairedData?.json?.group || profile.name || profile.group || 'Unknown').toUpperCase();

  groupBriefs.push({
    name: groupName,
    description: profile.description || '',
    locations: profile.locations || 'Unknown',
    profile_notes: profile.profile || [],
    victims: victims
  });
}

// Calculate threat level
const threatLevel = totalVictims > 50 ? '🔴 CRITICAL' : totalVictims > 20 ? '🟠 HIGH' : totalVictims > 10 ? '🟡 ELEVATED' : '🟢 MODERATE';

// Sort industries by impact
const topIndustries = Object.entries(industriesMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);

// ---- DEDUPLICATE AND AGGREGATE GROUPS ----
const groupedBriefsMap = {};

for (const g of groupBriefs) {
  if (!groupedBriefsMap[g.name]) {
    groupedBriefsMap[g.name] = {
      name: g.name,
      description: g.description,
      locations: g.locations,
      profile_notes: g.profile_notes,
      victims: []
    };
  }
  // Merge victims
  groupedBriefsMap[g.name].victims.push(...g.victims);
  // Keep first non-empty description
  if (!groupedBriefsMap[g.name].description && g.description) {
    groupedBriefsMap[g.name].description = g.description;
  }
  // Keep first non-empty locations
  if (groupedBriefsMap[g.name].locations === 'Unknown' && g.locations !== 'Unknown') {
    groupedBriefsMap[g.name].locations = g.locations;
  }
  // Merge profile notes
  if (Array.isArray(g.profile_notes) && g.profile_notes.length > 0) {
    groupedBriefsMap[g.name].profile_notes = [
      ...groupedBriefsMap[g.name].profile_notes,
      ...g.profile_notes
    ];
  }
}

const groupedBriefs = Object.values(groupedBriefsMap);

// ============================================================
// BUILD ENHANCED MARKDOWN REPORT
// ============================================================

let md = `# 🎯 RANSOMWARE THREAT INTELLIGENCE BRIEF\n\n`;
md += `**Report Date:** ${now} | **Classification:** CONFIDENTIAL\n`;
md += `**Threat Level:** ${threatLevel}\n\n`;
md += `---\n\n`;

// ---- EXECUTIVE DASHBOARD ----
md += `## 📊 EXECUTIVE DASHBOARD\n\n`;
md += `| Metric | Value | Status |\n`;
md += `|--------|-------|--------|\n`;
md += `| 🏴‍☠️ Active Threat Groups | ${groupedBriefs.length} | ${groupedBriefs.length > 15 ? '⚠️ High Activity' : '✅ Normal'} |\n`;
md += `| 🎯 Total Victims (Filtered) | ${totalVictims} | ${totalVictims > 30 ? '🔴 Critical' : '🟢 Manageable'} |\n`;
md += `| 🌍 Countries Affected | ${countriesSet.size} | ${countriesSet.size > 20 ? '🌐 Global' : '📍 Regional'} |\n`;
md += `| 🏭 Industries Targeted | ${Object.keys(industriesMap).length} | ${Object.keys(industriesMap).length > 10 ? '⚠️ Widespread' : '✅ Focused'} |\n`;
md += `\n---\n\n`;

// ---- THREAT LEVEL ASSESSMENT ----
md += `## 🚨 THREAT LEVEL ASSESSMENT\n\n`;
md += `**Current Status:** ${threatLevel}\n\n`;
md += `**Risk Indicators:**\n`;
md += `- 📈 Attack Frequency: ${totalVictims > 40 ? 'Very High' : totalVictims > 20 ? 'High' : 'Moderate'}\n`;
md += `- 🎯 Target Diversity: ${Object.keys(industriesMap).length} sectors affected\n`;
md += `- 🌐 Geographic Spread: ${countriesSet.size} countries\n`;
md += `- 👥 Active Groups: ${groupedBriefs.length} confirmed threat actors\n`;
md += `\n---\n\n`;

// ---- GEOGRAPHIC DISTRIBUTION ----
md += `## 🌍 GEOGRAPHIC DISTRIBUTION\n\n`;
const countryCount = {};
groupedBriefs.forEach(g => {
  g.victims.forEach(v => {
    if (v.country) countryCount[v.country] = (countryCount[v.country] || 0) + 1;
  });
});

const topCountries = Object.entries(countryCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 15);

md += `| Country | Victims | Heat Level |\n`;
md += `|---------|---------|------------|\n`;
topCountries.forEach(([country, count]) => {
  const heat = count > 5 ? '🔥🔥🔥' : count > 2 ? '🔥🔥' : '🔥';
  md += `| ${country} | ${count} | ${heat} |\n`;
});
md += `\n---\n\n`;

// ---- INDUSTRY IMPACT ANALYSIS ----
md += `## 🏭 INDUSTRY IMPACT ANALYSIS\n\n`;
md += `| Industry | Victims | % of Total | Risk Level |\n`;
md += `|----------|---------|------------|------------|\n`;
topIndustries.forEach(([industry, count]) => {
  const percentage = ((count / totalVictims) * 100).toFixed(1);
  const risk = count > 5 ? '🔴 Critical' : count > 2 ? '🟠 High' : '🟡 Medium';
  md += `| ${industry} | ${count} | ${percentage}% | ${risk} |\n`;
});
md += `\n---\n\n`;

// ---- TIMELINE ANALYSIS ----
if (discoveryDates.length > 0) {
  discoveryDates.sort((a, b) => b - a);
  const latest = discoveryDates[0];
  const oldest = discoveryDates[discoveryDates.length - 1];
  const daysDiff = Math.ceil((latest - oldest) / (1000 * 60 * 60 * 24));

  md += `## ⏱️ TIMELINE ANALYSIS\n\n`;
  md += `**Observation Period:** ${daysDiff} days\n`;
  md += `**Latest Discovery:** ${latest.toISOString().split('T')[0]}\n`;
  md += `**Oldest Discovery:** ${oldest.toISOString().split('T')[0]}\n`;
  md += `**Attack Velocity:** ${(totalVictims / Math.max(daysDiff, 1)).toFixed(2)} victims/day\n`;
  md += `\n---\n\n`;
}

// ---- THREAT OVERVIEW TABLE ----
md += `## 📋 THREAT GROUP OVERVIEW\n\n`;
md += `| Group | Victims | Industries Hit | Countries | Threat Score |\n`;
md += `|-------|---------|---------------|-----------|--------------|\n`;

for (const g of groupedBriefs) {
  const industries = [...new Set(g.victims.map(v => v.activity).filter(Boolean))].slice(0, 3).join(', ') || 'N/A';
  const countries = [...new Set(g.victims.map(v => v.country).filter(Boolean))].slice(0, 5).join(', ') || 'N/A';
  const victimCount = g.victims.length;
  const score = victimCount > 3 ? '⚠️⚠️⚠️' : victimCount > 1 ? '⚠️⚠️' : '⚠️';
  md += `| ${g.name} | ${victimCount} | ${industries} | ${countries} | ${score} |\n`;
}

md += `\n---\n\n`;

// ---- DETAILED GROUP PROFILES ----
md += `## 🔍 DETAILED THREAT GROUP PROFILES\n\n`;

for (const g of groupedBriefs) {
  md += `### 🏴‍☠️ ${g.name}\n\n`;

  // Threat metrics
  const victimCount = g.victims.length;
  const uniqueCountries = [...new Set(g.victims.map(v => v.country).filter(Boolean))].length;
  const uniqueIndustries = [...new Set(g.victims.map(v => v.activity).filter(Boolean))].length;

  md += `**Threat Metrics:**\n`;
  md += `- 🎯 Confirmed Victims: ${victimCount}\n`;
  md += `- 🌍 Geographic Reach: ${uniqueCountries} countries\n`;
  md += `- 🏭 Industry Targets: ${uniqueIndustries} sectors\n`;
  md += `- 📍 Suspected Origin: ${g.locations}\n\n`;

  if (g.description) {
    md += `**Intelligence Summary:**\n`;
    md += `${g.description.substring(0, 500)}...\n\n`;
  }

  if (g.profile_notes && g.profile_notes.length > 0) {
    md += `**Threat Intelligence Notes:**\n`;
    const notes = Array.isArray(g.profile_notes) ? g.profile_notes : [g.profile_notes];
    notes.slice(0, 3).forEach((note, idx) => {
      if (note && typeof note === 'string') {
        md += `${idx + 1}. ${note.substring(0, 300)}\n`;
      }
    });
    md += `\n`;
  }

  if (g.victims.length > 0) {
    md += `**Recent Victims (Redacted):**\n\n`;
    md += `| Company (Redacted) | Industry | Country | Discovered | Status |\n`;
    md += `|--------------------|----------|---------|------------|--------|\n`;
    g.victims.forEach(v => {
      const status = '🔴 Compromised';
      md += `| ${v.victim_redacted} | ${v.activity || 'N/A'} | ${v.country || 'N/A'} | ${v.discovered ? v.discovered.split(' ')[0] : 'N/A'} | ${status} |\n`;
    });
    md += `\n`;
  }

  md += `---\n\n`;
}

// ---- FOOTER ----
md += `## 📌 REPORT METADATA\n\n`;
md += `**Generated:** ${new Date().toISOString()}\n`;
md += `**Data Source:** ransomware.live API v2\n`;
md += `**Analysis Engine:** n8n Workflow Automation\n`;
md += `**Classification:** CONFIDENTIAL - INTERNAL USE ONLY\n\n`;
md += `---\n\n`;
md += `⚠️ **DISCLAIMER:** All victim names have been redacted for privacy and compliance.\n`;
md += `🔒 **SECURITY NOTICE:** This report contains sensitive threat intelligence. Handle accordingly.\n`;
md += `\n_Powered by ransomware.live API + n8n | SANS Webinar Demo_\n`;

// ============================================================
// BUILD ENHANCED SLACK SUMMARY
// ============================================================

let slack = `🚨 *RANSOMWARE THREAT BRIEF — ${now}*\n\n`;
slack += `*Threat Level:* ${threatLevel}\n`;
slack += `*Active Groups:* ${groupedBriefs.length} | *Victims:* ${totalVictims} | *Countries:* ${countriesSet.size}\n\n`;
slack += `📊 *TOP TARGETED INDUSTRIES:*\n`;
topIndustries.slice(0, 5).forEach(([industry, count]) => {
  slack += `• ${industry}: ${count} victims\n`;
});
slack += `\n🏴‍☠️ *ACTIVE THREAT GROUPS:*\n`;
groupedBriefs.slice(0, 10).forEach(g => {
  const industries = [...new Set(g.victims.map(v => v.activity).filter(Boolean))].slice(0, 2).join(', ');
  slack += `• *${g.name}* — ${g.victims.length} victim(s) | ${industries}\n`;
});
slack += `\n🔗 _Full intelligence brief available in Google Doc_\n`;
slack += `⚠️ _All victim identities redacted for security_`;

// ============================================================
// BUILD PLAIN TEXT FOR GOOGLE DOCS
// ============================================================

let plain = md
  .replace(/\*\*/g, '')
  .replace(/^#+\s/gm, '')
  .replace(/\|/g, ' | ')
  .replace(/🔴|🟠|🟡|🟢|🏴‍☠️|🎯|🌍|🏭|📊|🚨|📈|👥|🔥|⏱️|📋|🔍|📍|⚠️|🔒|📌/g, '');

// ============================================================
// RETURN ENHANCED OUTPUT
// ============================================================

return [{
  json: {
    markdown: md,
    slack_text: slack,
    google_doc_content: plain,
    group_count: groupedBriefs.length,
    victim_count: totalVictims,
    countries_affected: countriesSet.size,
    industries_affected: Object.keys(industriesMap).length,
    threat_level: threatLevel,
    top_industries: topIndustries,
    top_countries: topCountries,
    generated_at: now,
    report_type: 'ENHANCED_INTELLIGENCE_BRIEF'
  }
}];

// ============================================================
// EXTRACT UNIQUE THREAT GROUPS
// ============================================================
// Deduplicate ransomware groups and collect their victim
// lists so we fetch each group profile only once.
// ============================================================

const items = $input.all();

if (items.length === 1 && items[0].json.count === 0) {
  return [{ json: { no_results: true, message: items[0].json.message } }];
}

const groupMap = {};

for (const item of items) {
  const group = item.json.group;
  if (group && group !== 'Unknown') {
    if (!groupMap[group]) {
      groupMap[group] = [];
    }
    groupMap[group].push({
      victim_redacted: item.json.victim_redacted,
      activity: item.json.activity,
      country: item.json.country,
      discovered: item.json.discovered,
      attackdate: item.json.attackdate
    });
  }
}

const groups = Object.entries(groupMap).map(([name, victims]) => ({
  json: {
    group: name,
    victim_count: victims.length,
    victims: victims
  }
}));

return groups.length > 0
  ? groups
  : [{ json: { no_results: true, message: 'No groups identified' } }];

// No groups found in monitored industries — log it
return [{
  json: {
    status: 'clear',
    message: 'No ransomware activity detected in monitored industries this cycle.',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// OUTPUT MARKDOWN FILE
// ============================================================
// Creates a binary file output containing the markdown content
// from the consolidated brief.
// ============================================================

const items = $input.all();

if (items.length === 0 || !items[0].json.markdown) {
  return [{ json: { error: 'No markdown content found' } }];
}

const markdown = items[0].json.markdown;
const generatedAt = items[0].json.generated_at || new Date().toISOString().split('T')[0];
const fileName = `Ransomware_Threat_Brief_${generatedAt}.md`;

// Convert markdown to binary data
const binaryData = Buffer.from(markdown, 'utf-8');

return [{
  json: {
    fileName: fileName,
    fileSize: binaryData.length,
    generated_at: generatedAt
  },
  binary: {
    data: {
      data: binaryData.toString('base64'),
      mimeType: 'text/markdown',
      fileName: fileName
    }
  }
}];

// ============================================================
// GENERATE DIVERSE FAKE COMPANIES
// ============================================================
// Creates realistic fake company data with varied:
// - Company names (diverse, non-repeating)
// - Industries (matching real-world distribution)
// - Countries (global spread)
// - Discovery dates (varied timeline)
// ============================================================

const COMPANY_PREFIXES = [
  'Apex', 'Meridian', 'Cobalt', 'Zenith', 'Pinnacle', 'Vanguard',
  'Atlas', 'Horizon', 'Sterling', 'Quantum', 'Ironbridge', 'Cascade',
  'Summit', 'Pacific', 'Northwind', 'Redwood', 'Clearwater', 'Titan',
  'Evergreen', 'Beacon', 'Crimson', 'Delta', 'Eclipse', 'Frontier',
  'Genesis', 'Harbor', 'Imperial', 'Jade', 'Keystone', 'Liberty',
  'Majestic', 'Noble', 'Omega', 'Phoenix', 'Quantum', 'Regal',
  'Sapphire', 'Triumph', 'Unity', 'Velocity', 'Westgate', 'Zenith'
];

const COMPANY_SUFFIXES = [
  'Industrial Solutions', 'Health Partners', 'Financial Group', 'Technologies Inc',
  'Energy Corp', 'Public Services', 'Manufacturing Ltd', 'Medical Systems',
  'Capital Advisors', 'Dynamics Corp', 'Logistics', 'Healthcare Network',
  'Engineering Group', 'Trading Co', 'Aerospace', 'Pharmaceuticals',
  'Data Systems', 'Defense Industries', 'Supply Chain', 'Analytics Group',
  'Consulting', 'Retail Group', 'Construction', 'Legal Services',
  'Insurance Co', 'Software Solutions', 'Telecom', 'Transportation',
  'Hospitality Group', 'Education Services'
];

const INDUSTRIES = [
  'Financial Services', 'Healthcare', 'Manufacturing', 'Technology',
  'Energy', 'Retail', 'Construction', 'Legal Services',
  'Insurance', 'Education', 'Transportation', 'Hospitality',
  'Telecommunications', 'Pharmaceuticals', 'Aerospace', 'Government'
];

const COUNTRIES = [
  'US', 'GB', 'DE', 'FR', 'CA', 'AU', 'JP', 'IT', 'ES', 'NL',
  'SE', 'CH', 'BE', 'AT', 'DK', 'NO', 'FI', 'IE', 'NZ', 'SG',
  'BR', 'MX', 'IN', 'KR', 'TW', 'HK', 'IL', 'PL', 'CZ', 'GR'
];

function randomElement(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

function generateUniqueName(usedNames) {
  let attempts = 0;
  let name;
  do {
    const prefix = randomElement(COMPANY_PREFIXES);
    const suffix = randomElement(COMPANY_SUFFIXES);
    name = `${prefix} ${suffix}`;
    attempts++;
  } while (usedNames.has(name) && attempts < 100);

  usedNames.add(name);
  return name;
}

function randomDate(daysBack) {
  const now = new Date();
  const randomDays = Math.floor(Math.random() * daysBack);
  const date = new Date(now.getTime() - (randomDays * 24 * 60 * 60 * 1000));
  return date.toISOString().split('T')[0] + ' ' + 
         date.toTimeString().split(' ')[0] + '.' + 
         Math.floor(Math.random() * 1000000);
}

const items = $input.all();
const result = [];
const usedNames = new Set();

for (const item of items) {
  const v = item.json;
  result.push({
    json: {
      victim_redacted: generateUniqueName(usedNames),
      group: v.group || 'Unknown',
      activity: randomElement(INDUSTRIES),
      country: randomElement(COUNTRIES),
      discovered: randomDate(30),
      attackdate: randomDate(35),
      description: v.description || '',
      infostealer: v.infostealer || false,
      press: v.press || false,
      domain: '[REDACTED]',
      url: '[REDACTED]',
      claim_url: '[REDACTED]',
      screenshot: '[REDACTED]'
    }
  });
}

return result;

