// ============================================================
// ENHANCE BRIEF WITH AI ANALYSIS
// ============================================================
// Combines the consolidated threat brief with AI-generated
// threat intelligence analysis and TTPs
// ============================================================

const briefData = $('Build Consolidated Brief').first().json;
const aiAnalysis = $input.first().json.output || {};

// Extract AI analysis components
const threatLevel = aiAnalysis.threat_level || 'UNKNOWN';
const ttps = aiAnalysis.ttps || [];
const targeting = aiAnalysis.targeting_patterns || {};
const opIntel = aiAnalysis.operational_intelligence || 'No analysis available';
const recommendations = aiAnalysis.recommendations || [];

// Build AI Analysis Section for Markdown
let aiSection = `\n\n---\n\n## 🤖 AI THREAT INTELLIGENCE ANALYSIS\n\n`;
aiSection += `**AI Threat Assessment:** ${threatLevel}\n\n`;

if (ttps.length > 0) {
  aiSection += `### 🎯 Observed TTPs (Tactics, Techniques, and Procedures)\n\n`;
  aiSection += `| Tactic | Technique | Description |\n`;
  aiSection += `|--------|-----------|-------------|\n`;
  ttps.forEach(ttp => {
    aiSection += `| ${ttp.tactic || 'N/A'} | ${ttp.technique || 'N/A'} | ${ttp.description || 'N/A'} |\n`;
  });
  aiSection += `\n`;
}

if (targeting.industries || targeting.regions) {
  aiSection += `### 🎯 Targeting Analysis\n\n`;
  if (targeting.industries && targeting.industries.length > 0) {
    aiSection += `**Primary Industry Targets:** ${targeting.industries.join(', ')}\n\n`;
  }
  if (targeting.regions && targeting.regions.length > 0) {
    aiSection += `**Geographic Focus:** ${targeting.regions.join(', ')}\n\n`;
  }
  if (targeting.victim_profile) {
    aiSection += `**Victim Profile:** ${targeting.victim_profile}\n\n`;
  }
}

if (opIntel) {
  aiSection += `### 🔍 Operational Intelligence\n\n`;
  aiSection += `${opIntel}\n\n`;
}

if (recommendations.length > 0) {
  aiSection += `### 🛡️ Defensive Recommendations\n\n`;
  recommendations.forEach((rec, idx) => {
    aiSection += `${idx + 1}. ${rec}\n`;
  });
  aiSection += `\n`;
}

// Insert AI section before the metadata section
let enhancedMarkdown = briefData.markdown;
const metadataIndex = enhancedMarkdown.indexOf('## 📌 REPORT METADATA');
if (metadataIndex > -1) {
  enhancedMarkdown = enhancedMarkdown.slice(0, metadataIndex) + 
                     aiSection + 
                     enhancedMarkdown.slice(metadataIndex);
} else {
  enhancedMarkdown += aiSection;
}

// Add AI summary to Slack text
let enhancedSlack = briefData.slack_text;
enhancedSlack += `\n\n🤖 *AI ANALYSIS:*\n`;
enhancedSlack += `• Threat Level: ${threatLevel}\n`;
if (ttps.length > 0) {
  enhancedSlack += `• TTPs Identified: ${ttps.length}\n`;
}
if (recommendations.length > 0) {
  enhancedSlack += `• Recommendations: ${recommendations.length}\n`;
}

return [{
  json: {
    ...briefData,
    markdown: enhancedMarkdown,
    slack_text: enhancedSlack,
    ai_analysis: {
      threat_level: threatLevel,
      ttps: ttps,
      targeting_patterns: targeting,
      operational_intelligence: opIntel,
      recommendations: recommendations
    }
  }
}];
